const q = $json.query ?? {};
const adId = String(q.ad_id ?? q.adId ?? "").trim();
if (!adId) throw new Error("ad_id query param required");
return [{ json: { adId } }];

const adId = $('Precheck - Extract Ad ID').item.json.adId;
const rows = $input.all();

// Test patterns
if (adId.startsWith('AD-NON-ACTIVE-')) {
  return [{ json: { statusCode: 200, body: { id: adId, name: 'Test Ad (Non-Active)',
    status: 'PAUSED', effective_status: 'PAUSED' } } }];
}
if (adId.startsWith('AD-RETRY-')) {
  return [{ json: { statusCode: 200, body: { id: adId, name: 'Test Ad (Retry)',
    status: 'ACTIVE', effective_status: 'ACTIVE' } } }];
}

// GSheet lookup
const match = rows.find(r => r.json.ad_id === adId);
if (!match) {
  return [{ json: { statusCode: 200, body: { id: adId, name: 'Test Ad ' + adId,
    status: 'ACTIVE', effective_status: 'ACTIVE' } } }];
}
const row = match.json;
return [{ json: { statusCode: 200, body: {
  id: row.ad_id, name: row.ad_name, status: row.status, effective_status: row.status
} } }];

const body = $json.body ?? $json;
const adId = String(body.ad_id ?? body.adId ?? "").trim();
if (!adId) throw new Error("ad_id required");
return [{ json: { adId } }];

const src = $('Pause - Extract Ad ID').item.json;
const adId = src.adId;
const rows = $input.all();

// AD-RETRY-* returns 429 (rate limit)
if (adId.startsWith('AD-RETRY-')) {
  return [{ json: { statusCode: 429, body: { error: { message: 'Rate limit exceeded', code: 4 } } } }];
}

// Normal path: pause success
return [{ json: { statusCode: 200, body: { success: true, id: adId } } }];

const pattern = String($('Mock List Ads Webhook').item.json.query?.pattern ?? '').trim();
const allRows = $input.all();
let filtered = allRows;
if (pattern) {
  try {
    const regex = new RegExp(pattern, 'i');
    filtered = allRows.filter(item => regex.test(item.json.ad_name ?? ''));
  } catch (e) { filtered = []; }
}
const data = filtered.map(item => ({ id: item.json.ad_id, name: item.json.ad_name, status: item.json.status, effective_status: item.json.status, campaign_name: item.json.campaign_name ?? '' }));
return [{ json: { statusCode: 200, body: { data, paging: { cursors: { before: '', after: '' } } } } }];

